import { formatCitation } from '@/lib/utils/citation-formatter';

const paperId = 'paper-123';

// APA style
const apa = formatCitation(paperId, 'APA');
// "Smith, J. (2020). Machine Learning in Research. Journal of AI, 15(3)."

// MLA style
const mla = formatCitation(paperId, 'MLA');
// "Smith, John. \"Machine Learning in Research.\" Journal of AI, 15.3 (2020)."

// Chicago style
const chicago = formatCitation(paperId, 'Chicago');
// "Smith, John. \"Machine Learning in Research.\" Journal of AI. Accessed 2026-02-08."

// Harvard style
const harvard = formatCitation(paperId, 'Harvard');
// "Smith, J 2020, Machine Learning in Research, Journal of AI, viewed 8 February 2026."

